var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"놈들의 기세가 약해지고 있습니다!","JPN":"やつらの勢いが弱まっています！","ENG":"The enemy's momentum is fading!","TWN":"敵人的氣勢在減弱！"},"stage":{"bg":"ROOT_VILLAGE_B","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"승산이 보인다! 이대로만 버텨!","JPN":"勝利が目の前だ！　このまま耐えろ！","ENG":"Victory is in sight! Just hold!","TWN":"有勝算了！就這樣撐住！"},"stage":{"bg":"ROOT_VILLAGE_B","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOT_VILLAGE_B","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"하지만 의문이 남는군.","JPN":"だが、疑問が残るな。","ENG":"But a question remains.","TWN":"不過還是有疑問。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"우리가 가장 경계해야 할 존재가 아직도 그 모습을 드러내지 않다니.","JPN":"私たちがもっとも警戒すべき存在が、まだその姿を現していない。","ENG":"The entity we are most wary of has yet to reveal itself.","TWN":"我們最應該警惕的存在還沒有現身。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"뭔가… 이상하네요.","JPN":"何か……おかしいですね。","ENG":"Something... is strange.","TWN":"有點…奇怪。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마물들은 마치 누군가의 명령을 받는 것처럼 움직이는데, 정작 그 통솔자가 보이지 않아요.","JPN":"魔物たちは何者かに命令されたように動いてるのに、その統率者が見当たりません。","ENG":"The monsters move as if they are receiving orders from someone, but that leader is nowhere in sight.","TWN":"怪物們像是受到了某人的命令在行動，但那個指揮者卻始終沒有現身。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"어쩌면, 제사장께서 동토로 나아가신 것과 연관이 있을지도 모르겠군요.","JPN":"もしかしたら、祭祀長が凍土に出たのと関係があるのかもしれませんね。","ENG":"Perhaps it has something to do with the High Priest setting out to the gelid lands.","TWN":"或許，這與祭司長前去了凍土有關。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"멀린 씨가 그루터기 밖으로 떠났다고요?","JPN":"マーリンさんが切り株の外に出たんですか？","ENG":"Merlin left the Stump?","TWN":"梅林祭司長離開了木墩？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"나무의 가능성을 빌려 겨우 이성을 유지하고 있긴 하지만…","JPN":"切り株の可能性を借りてなんとか理性を保っているけれど……","ENG":"I have been able to maintain my sanity by borrowing the Stump's possibilities...","TWN":"雖然借助著木墩中的可能性勉強維持理智…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그루터기에서 멀어지거나 그 수명이 다하는 날엔 나도 그 후작 녀석과 똑같은 괴물이 되겠지.","JPN":"切り株から離れたり、その命が尽きる日にはアタシも侯爵と同じ怪物になるでしょうね。","ENG":"But if I leave the Stump or the Stump's life comes to an end, I will become a monster like Marquis.","TWN":"但一旦離開這裡或者壽命終結，我也會變成和那個侯爵一樣的怪物。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"제사장님께선 정착 이래, 한 번도 그루터기를 떠나신 적이 없다고 들었습니다.","JPN":"祭祀長は定住して以来、一度も切り株から出たことがないと聞きました。","ENG":"I heard High Priest Merlin has never set foot outside of the Stump since settling down here.","TWN":"我聽說祭司長自祖先定居以來，從未離開過木墩。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이번에 저희가 맞닥뜨린 시련이 평소와는 다르다는 반증이겠지요.","JPN":"今回私たちを襲った試練が、いつもとは違うという証拠でしょう。","ENG":"This may be proof that the ordeal we face now is out of the ordinary.","TWN":"或許我們這次面臨的考驗與以往不同…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"키안… 저기…!","JPN":"キアン……あそこ……！","ENG":"Kian... Um...!","TWN":"奇恩爺爺…那個…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"제사장님께선 동쪽으로 향하셨습니다.","JPN":"祭祀長は東の方に向かいました。","ENG":"She headed east.","TWN":"祭司長向東去了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"여긴 저희에게 맡기고 가십시오.","JPN":"ここは私たちに任せて、行ってください。","ENG":"Leave this place to us.","TWN":"這裡交給我們吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그래도 괜찮을까요?","JPN":"それでも大丈夫でしょうか？","ENG":"Are you sure?","TWN":"這樣可以嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"그루터기를 지키라는 명을 받은 이상, 저희는 함부로 그 뜻을 어길 수 없습니다.","JPN":"切り株を守れと命じられた以上、私たちはその意志に反することはできません。","ENG":"As long as we are commanded to protect the Stump, we cannot disobey it so easily.","TWN":"既然接到了守護木墩的命令，我們便不能隨意違背。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"하지만 성자님은 그루터기의 규칙에 얽매이지 않은 분이죠.","JPN":"ですが聖者様は、切り株の規則に縛られていない。","ENG":"However, you are not bound by the rules of the Stump.","TWN":"但是聖者是不受木墩規則束縛的人。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"그러니 감히 부탁드리겠습니다.","JPN":"だから、お願いします。","ENG":"So, I plead with you.","TWN":"所以請你幫忙。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"부디 제사장님을 도와주십시오.","JPN":"どうか祭祀長を助けてください。","ENG":"Please help our High Priest.","TWN":"請你幫助祭司長。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"걱정마세요.","JPN":"わかりました。","ENG":"Don't worry.","TWN":"不要擔心。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"반드시, 멀린 씨를 데려올게요.","JPN":"必ず、マーリンさんを連れてきます。","ENG":"I'll return with Merlin, no matter what.","TWN":"我一定會帶梅林祭司長回來。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};